"use client";

import { useEffect, useState } from "react";

interface Particle {
  id: number;
  x: string;
  y: string;
  size: string;
  duration: string;
  delay: string;
  drift: string;
}

export function AmbientParticles() {
  const [particles, setParticles] = useState<Particle[]>([]);

  useEffect(() => {
    // Generate 18-22 particles
    const count = Math.floor(Math.random() * 5) + 18;
    const items = Array.from({ length: count }).map((_, i) => ({
      id: i,
      x: `${Math.random() * 100}%`,
      y: `${Math.random() * 100}%`,
      size: `${(Math.random() * 1.5 + 1).toFixed(1)}px`,
      duration: `${(Math.random() * 10 + 12).toFixed(1)}s`,
      delay: `${(Math.random() * -20).toFixed(1)}s`,
      drift: `${(Math.random() * 40 - 20).toFixed(1)}px`,
    }));
    setParticles(items);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden select-none" aria-hidden="true">
      {particles.map((p) => (
        <div
          key={p.id}
          className="absolute rounded-full animate-particle-drift"
          style={{
            left: p.x,
            top: p.y,
            width: p.size,
            height: p.size,
            backgroundColor: "rgba(180, 140, 120, 0.25)",
            animationDuration: p.duration,
            animationDelay: p.delay,
            "--drift-x": p.drift,
          } as React.CSSProperties & { [key: string]: string }}
        />
      ))}
      <style dangerouslySetInnerHTML={{
        __html: `
        @keyframes particle-drift {
          0% {
            transform: translateY(0) translateX(0);
            opacity: 0;
          }
          10% {
            opacity: 1;
          }
          90% {
            opacity: 1;
          }
          100% {
            transform: translateY(-100vh) translateX(var(--drift-x));
            opacity: 0;
          }
        }
        .animate-particle-drift {
          animation-name: particle-drift;
          animation-timing-function: linear;
          animation-iteration-count: infinite;
        }
      `}} />
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";

/**
 * CONFIG: To update the rotating personal detail, simply add/remove strings from this array.
 */
const pool = [
    "somewhere between fine and not",
    "rereading old notes",
    "a book with a broken spine",
    "half a thought and a full cup of tea",
    "learning to sit with it",
    "listening to the same song again"
];

export function CurrentlyDetail() {
    const [status, setStatus] = useState<string>("");

    useEffect(() => {
        // Pick a random status from the pool on each refresh
        const randomStatus = pool[Math.floor(Math.random() * pool.length)];
        setStatus(randomStatus);
    }, []); // eslint-disable-line react-hooks/exhaustive-deps

    if (!status) return null;

    return (
        <div className="hidden sm:block opacity-60">
            <p className="font-body text-[11px] md:text-[12px] text-[var(--color-ink-muted)] lowercase text-right">
                currently: {status}
            </p>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";

const fragments = [
    "written in the thick of it",
    "a quieter week than expected",
    "still thinking about tuesday",
    "the window was open",
    "between two songs",
    "something that wouldn't leave",
    "after the third cup of tea",
    "a feeling with no name yet"
];

export function MicroTagline() {
    const [fragment, setFragment] = useState<string>("");
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        // Select random fragment on mount
        const randomFragment = fragments[Math.floor(Math.random() * fragments.length)];
        setFragment(randomFragment);

        // Fade in after page loads (short delay to ensure layout is ready)
        const timer = setTimeout(() => {
            setIsVisible(true);
        }, 100);

        return () => clearTimeout(timer);
    }, []); // eslint-disable-line react-hooks/exhaustive-deps

    if (!fragment) return <div className="h-[20px]" />; // Spacer to prevent jump

    return (
        <p
            className={`font-display italic text-[13px] md:text-[14px] text-[var(--accent-general)] transition-opacity duration-[400ms] ease-in-out ${isVisible ? "opacity-100" : "opacity-0"
                }`}
            style={{ pointerEvents: "none" }}
        >
            ÔåÆ {fragment}
        </p>
    );
}
